require __DIR__.'/../includes/bootstrap.php';require_admin();if(!universe_engine_ready())redirect('../upgrade-universes.php');
$error='';$editId=(int)($_GET['edit']??0);$requestedParent=(int)($_GET['parent']??0);$edit=null;
if($editId){$s=db()->prepare('SELECT * FROM universes WHERE id=?');$s->execute([$editId]);$edit=$s->fetch()?:null;}
if($_SERVER['REQUEST_METHOD']==='POST'){
 verify_csrf();$action=$_POST['action']??'';
 try{
  if($action==='save'){
   $id=(int)($_POST['id']??0);$name=trim($_POST['name']??'');if($name==='')throw new RuntimeException('Universe name is required.');
   $parent=(int)($_POST['parent_id']??0);if($parent===$id&&$id>0)throw new RuntimeException('A universe cannot be its own parent.');
   $slug=universe_slug($name,$id?:null);$values=[
    'parent_id'=>$parent?:null,'name'=>$name,'slug'=>$slug,'icon'=>trim($_POST['icon']??''),'short_description'=>trim($_POST['short_description']??''),'description'=>trim($_POST['description']??''),'status'=>in_array($_POST['status']??'draft',['draft','pending','approved','suspended'],true)?$_POST['status']:'draft','is_active'=>isset($_POST['is_active'])?1:0,'is_featured'=>isset($_POST['is_featured'])?1:0,
    'primary_color'=>$_POST['primary_color']??'#6f4cff','secondary_color'=>$_POST['secondary_color']??'#15172a','accent_color'=>$_POST['accent_color']??'#27d7ff','background_color'=>$_POST['background_color']??'#070812','surface_color'=>$_POST['surface_color']??'#111321','text_color'=>$_POST['text_color']??'#f7f7fb','display_font'=>trim($_POST['display_font']??''),'body_font'=>trim($_POST['body_font']??''),'texture_style'=>trim($_POST['texture_style']??''),'icon_style'=>trim($_POST['icon_style']??''),'imagery_treatment'=>trim($_POST['imagery_treatment']??''),'sort_order'=>(int)($_POST['sort_order']??0)
   ];
   if($id){
    $logo=universe_image_upload('logo','logos',$id);$banner=universe_image_upload('banner','banners',$id);
    $sql='UPDATE universes SET parent_id=:parent_id,name=:name,slug=:slug,icon=:icon,short_description=:short_description,description=:description,status=:status,is_active=:is_active,is_featured=:is_featured,primary_color=:primary_color,secondary_color=:secondary_color,accent_color=:accent_color,background_color=:background_color,surface_color=:surface_color,text_color=:text_color,display_font=:display_font,body_font=:body_font,texture_style=:texture_style,icon_style=:icon_style,imagery_treatment=:imagery_treatment,sort_order=:sort_order'.($logo?',logo_path=:logo_path':'').($banner?',banner_path=:banner_path':'').' WHERE id=:id';if($logo)$values['logo_path']=$logo;if($banner)$values['banner_path']=$banner;$values['id']=$id;db()->prepare($sql)->execute($values);
   }else{
    $values['created_by']=(int)user()['id'];$cols=implode(',',array_keys($values));$marks=':'.implode(',:',array_keys($values));db()->prepare("INSERT INTO universes({$cols}) VALUES({$marks})")->execute($values);$id=(int)db()->lastInsertId();
    $logo=universe_image_upload('logo','logos',$id);$banner=universe_image_upload('banner','banners',$id);if($logo||$banner){$sets=[];$a=['id'=>$id];if($logo){$sets[]='logo_path=:logo';$a['logo']=$logo;}if($banner){$sets[]='banner_path=:banner';$a['banner']=$banner;}db()->prepare('UPDATE universes SET '.implode(',',$sets).' WHERE id=:id')->execute($a);}
   }
   flash('success','Universe saved.');redirect('admin/universes.php?edit='.$id);
  }
  if($action==='delete'){$id=(int)$_POST['id'];$count=db()->prepare('SELECT COUNT(*) FROM universes WHERE parent_id=?');$count->execute([$id]);if((int)$count->fetchColumn()>0)throw new RuntimeException('Move or delete child universes first.');db()->prepare('DELETE FROM universes WHERE id=?')->execute([$id]);flash('success','Universe deleted.');redirect('admin/universes.php');}
 }catch(Throwable $e){$error=$e->getMessage();}
}
$all=db()->query("SELECT u.*,p.name parent_name,(SELECT COUNT(*) FROM user_universes uu WHERE uu.universe_id=u.id) member_count,(SELECT COUNT(*) FROM universes c WHERE c.parent_id=u.id) child_count FROM universes u LEFT JOIN universes p ON p.id=u.parent_id ORDER BY COALESCE(p.sort_order,u.sort_order),u.parent_id IS NOT NULL,u.sort_order,u.name")->fetchAll();
$parentRows=db()->query('SELECT id,parent_id,name FROM universes ORDER BY sort_order,name')->fetchAll();
$byParent=[];foreach($parentRows as $row)$byParent[(int)($row['parent_id']??0)][]=$row;
$parentOptions=[];$walk=function($parent,$depth) use (&$walk,&$byParent,&$parentOptions){foreach($byParent[$parent]??[] as $row){$row['depth']=$depth;$parentOptions[]=$row;$walk((int)$row['id'],$depth+1);}};$walk(0,0);
app_header('Universe Administration');
?><section class="dashboard-hero"><p class="eyebrow">ADMINISTRATION</p><h1>Universe Engine</h1><p>Create nested universes and define the skin each one applies to the shared site shell.</p></section><?php if($error):?><div class="alert error"><?=e($error)?></div><?php endif?><section class="admin-universe-layout"><form class="app-card universe-editor" method="post" enctype="multipart/form-data"><?=csrf_field()?><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=$edit['id']??0?>"><h2><?=$edit?'Edit Universe':'Create Universe'?></h2><div class="form-grid"><label>Name<input name="name" required value="<?=e($edit['name']??'')?>"></label><label>Parent universe<select name="parent_id"><option value="0">Root universe</option><?php $selectedParent=(int)($edit['parent_id']??$requestedParent);foreach($parentOptions as $p):if($edit&&(int)$p['id']===(int)$edit['id'])continue;?><option value="<?=$p['id']?>" <?=$selectedParent===(int)$p['id']?'selected':''?>><?=e(str_repeat('— ',(int)$p['depth']).$p['name'])?></option><?php endforeach?></select><small>Choose where this universe lives. Example: Comics → Marvel → Spider-Man.</small></label><label>Icon or emoji<input name="icon" value="<?=e($edit['icon']??'')?>"></label><label>Sort order<input type="number" name="sort_order" value="<?=e((string)($edit['sort_order']??0))?>"></label><label class="full">Short description<input name="short_description" maxlength="255" value="<?=e($edit['short_description']??'')?>"></label><label class="full">Description<textarea name="description" rows="5"><?=e($edit['description']??'')?></textarea></label><label>Status<select name="status"><?php foreach(['draft','pending','approved','suspended'] as $st):?><option value="<?=$st?>" <?=($edit['status']??'approved')===$st?'selected':''?>><?=ucfirst($st)?></option><?php endforeach?></select></label><label>Logo<input type="file" name="logo" accept="image/*"></label><label>Banner<input type="file" name="banner" accept="image/*"></label><label><input type="checkbox" name="is_active" <?=($edit['is_active']??1)?'checked':''?>> Active</label><label><input type="checkbox" name="is_featured" <?=($edit['is_featured']??0)?'checked':''?>> Featured</label></div><h3>Universe Skin</h3><div class="theme-field-grid"><?php foreach(['primary_color'=>'Primary','secondary_color'=>'Secondary','accent_color'=>'Accent','background_color'=>'Background','surface_color'=>'Surface','text_color'=>'Text'] as $key=>$label):?><label><?=$label?><input type="color" name="<?=$key?>" value="<?=e($edit[$key]??['primary_color'=>'#6f4cff','secondary_color'=>'#15172a','accent_color'=>'#27d7ff','background_color'=>'#070812','surface_color'=>'#111321','text_color'=>'#f7f7fb'][$key])?>"></label><?php endforeach?></div><div class="form-grid"><label>Display font<input name="display_font" value="<?=e($edit['display_font']??'')?>" placeholder="e.g. Cinzel"></label><label>Body font<input name="body_font" value="<?=e($edit['body_font']??'')?>" placeholder="e.g. Inter"></label><label>Texture language<input name="texture_style" value="<?=e($edit['texture_style']??'')?>" placeholder="Parchment, circuit lines..."></label><label>Iconography style<input name="icon_style" value="<?=e($edit['icon_style']??'')?>"></label><label class="full">Imagery treatment<input name="imagery_treatment" value="<?=e($edit['imagery_treatment']??'')?>" placeholder="High contrast, halftone, illustrated..."></label></div><button class="button primary">Save Universe</button><?php if($edit):?><a class="button ghost" href="universes.php">Create another</a><?php endif?></form><div class="table-wrap"><table><thead><tr><th>Universe</th><th>Parent</th><th>Status</th><th>Members</th><th>Sub-Universes</th><th></th></tr></thead><tbody><?php foreach($all as $u):?><tr><td><?=e(($u['icon']?' '.$u['icon'].' ':'').$u['name'])?></td><td><?=e($u['parent_name']?:'Root')?></td><td><?=e(ucfirst($u['status']))?></td><td><?=number_format((int)$u['member_count'])?></td><td><?=number_format((int)$u['child_count'])?></td><td><a class="button ghost small" href="?edit=<?=$u['id']?>">Edit</a> <a class="button ghost small" href="?parent=<?=$u['id']?>">Add Child</a> <a class="button ghost small" href="<?=e(base_url('universe/view.php?slug='.urlencode($u['slug'])))?>">View</a></td></tr><?php endforeach?></tbody></table></div></section><?php app_footer();
